module RefModule(clk,rst,In,Out);input clk, rst;
	input[31:0] In;

	output[31:0] Out;
	reg[31:0] Out;

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rst or posedge dbg_halt)
	begin
		if(!rst)
			Out <= 32'd0;
		else
			Out <= In;
	end

endmodule
